<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="500rpx" :closeable="true" @open="open" @close="close">
		<view class="popup-content">
			<view class="title">
				{{title}}
			</view>
			<view class="qrcode">
				<uqrcode v-if="!qrcodeImage" @complete="uqrcodeComplete" ref="uqrcode" @longpress="saveqrcode"
					canvas-id="qrcode" sizeUnit="rpx" size="300" :value="qrcodeUrl"></uqrcode>
				<image style="width: 100%;height: 100%;" v-else :src="qrcodeImage" mode="aspectFit">
				</image>
			</view>
			<view @click="copyLink">
				<view>点击复制链接或截图扫码</view>
			</view>
		</view>
	</u-popup>
</template>

<script>
	export default {
		components: {},
		props: {

		},
		data() {
			return {
				title: '',
				popupShow: false,
				qrcodeUrl: '',
				qrcodeImage: '',

				certifyType: '',
			}
		},
		computed: {},
		watch: {},
		created() {},
		mounted() {},
		methods: {
			show({
				url,
				name,
				type
			}) {
				if (url) {
					this.title = name
					this.certifyType = type
					this.qrcodeUrl = url
					this.popupShow = true
				}
			},
			open() {
				if (this.certifyType == 'authentication') {
					// 通过浏览器，打开支付宝app
					this.$util.openAppUrl(this.qrcodeUrl)
				}
			},
			close() {
				this.stopCheck()
			},
			//二维码生成成功
			uqrcodeComplete(e) {
				this.$refs.uqrcode.toTempFilePath({
					success: res => {
						this.qrcodeImage = res.tempFilePath
						this.checkStatus()
					}
				});
			},
			checkStatus() {
				this.timer = setInterval(() => {
					this.$u.api.certifyCallback().then((res) => {
						const {
							status
						} = res
						if (status == 1) {
							this.popupShow = false
							this.$emit('success', {
								msg: '认证成功'
							})
						} else if (status == 2) {
							this.popupShow = false
							this.$emit('fail', {
								msg: '认证失败'
							})
						}
					})
				}, 2000)
			},
			stopCheck() {
				if (this.timer) {
					clearInterval(this.timer)
					this.timer = null
				}
			},
			copyLink() {
				uni.setClipboardData({
					data: this.qrcodeUrl,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
		}
	}
</script>


<style scoped lang="scss" scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		&>.title {
			font-weight: bolder;
			font-size: 30rpx;
		}

		.qrcode {
			width: 300rpx;
			height: 300rpx;
		}
	}
</style>