<template>
	<view>
		<u-upload ref="uUpload" :fileList="fileList" :action="postUrl" :header="header"
			@on-success="handleUploadSuccess" :multiple="multiple" :maxCount="maxCount"
			:previewFullImage="previewFullImage" :customBtn="customBtn" :uploadText="uploadText" :width="width"
			:height="height" @on-remove="handleRemove" :show-progress="showProgress">
			<template v-if="customBtn">
				<view slot="addBtn" class="custom-add-btn"
					:style="{width:`${width}rpx`,height:`${height}rpx`,color:addBtnColor}">
					<u-icon :name="addBtnIconName" :size="addBtnIconSize" :color="addBtnColor" />
					<text class="f20">{{uploadText}}</text>
				</view>
			</template>
		</u-upload>
	</view>
</template>

<script>
	import config from "@/common/config"
	import _ from 'lodash'

	export default {
		name: "upload",
		data() {
			return {
				fileList: [],
			};
		},
		props: {
			value: {
				type: [Array, String],
				required: false,
				default: () => ([])
			},
			multiple: {
				type: Boolean,
				default: false,
			},
			maxCount: {
				type: Number,
				default: 1
			},
			width: {
				type: Number,
				default: 160
			},
			height: {
				type: Number,
				default: 160
			},
			previewFullImage: {
				type: Boolean,
				default: true
			},
			showProgress: {
				type: Boolean,
				default: false,
			},
			uploadText: {
				type: String,
				default: '上传图片'
			},
			customBtn: {
				type: Boolean,
				default: false
			},
			addBtnIconName: {
				type: String,
				default: 'plus'
			},
			addBtnIconSize: {
				type: Number,
				default: 60
			},
			addBtnColor: {
				type: String,
				default: '#333'
			}
		},
		watch: {},
		mounted() {
			let arr = []
			if (this.multiple) {
				this.value.map(item => {
					arr.push({
						url: item,
					})
				})
				this.fileList = arr
			} else {
				if (this.value) {
					this.fileList = [{
						url: this.value
					}]
				}
			}
		},
		computed: {
			postUrl() {
				return config.apiurl + '/uni/upload'
			},
			header() {
				return {
					'authorization': 'Bearer ' + uni.getStorageSync('token'),
					'sign': this.$util.reqSign(),
				}
			}
		},
		methods: {
			handleUploadSuccess(response, index, fileList) {
				if (response.code !== 200) { // 根据接口返回判断
					this.$util.msg(response.msg)
					// 移除失败的文件
					this.$refs.uUpload.remove(index)
				} else {
					if (this.multiple) {
						this.$emit('input', this.getFileSrc(fileList))
					} else {
						const list = this.getFileSrc(fileList)
						if (list.length > 0)
							this.$emit('input', list[0])
						else
							this.$emit('input', '')
					}
				}
			},
			handleRemove(index, fileList) {
				if (this.multiple) {
					this.$emit('input', this.getFileSrc(fileList))
				} else {
					const list = this.getFileSrc(fileList)
					if (list.length > 0)
						this.$emit('input', list[0])
					else
						this.$emit('input', '')
				}
			},
			getFileSrc(fileList) {
				let re = []
				fileList.forEach(item => {
					if (Reflect.has(item, 'response')) {
						if (item.response.code == 200) {
							re.push(_.get(item, 'response.data.src', ''))
						}
					} else {
						re.push(item.url)
					}
				})
				return re
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.custom-add-btn {
		display: flex;
		flex-direction: column;
		justify-content: center;
		align-items: center;
		gap: 10rpx;
		padding: 20rpx 16rpx 8rpx 16rpx;
		background-color: rgba(221, 221, 221, .3);
		border-radius: 10rpx;
	}
</style>