<template>
	<view class="body">


		<view class="box">
			<view class="box-child">
				<view class="recharge-box" v-show="type == 1">
					<view class="title">
						<view class="left">
							提现金额
						</view>
						<view class="type">
							<view class="" style="color: #303133;border: 2rpx solid #ccc;
    border-radius: 20rpx;
    padding: 0 12rpx;" @click="$util.on('/pages/ucenter_sub/drawlo')">
								提现记录
							</view>
							<!-- #ifdef MP -->
							<!-- 微信小程序不让提现-->
							<!-- #endif -->
							<!-- #ifndef MP -->
							<view class="" style="color: #303133;border: 2rpx solid #ccc;
    border-radius: 20rpx;
    padding: 0 12rpx;" @click="showform = true">
								添加提现方式
							</view>
							<!-- #endif -->

							<view class="" style="border: 2rpx solid;
    border-radius: 20rpx;
    padding: 0 12rpx;" @click="$util.on('/pages/ucenter_sub/drawmode')">
								提现方式
							</view>
						</view>

					</view>
					<view class="form-item">
						<text class="label">
							￥
						</text>
						<u-input :custom-style="{
							color: '#1e2331',
							fontWeight: 600,
							fontSize: '64rpx',
						}" v-model="money" placeholder="请输入提现金额" placeholder-style="color:#d8d8d8;font-size:30rpx;font-wight:400;"
							@input="moneyInput" />
					</view>

					<view class="tips">
						<view>提现规则：{{feerule.collectruleshow}}</view>
						<view>最小提现金额： {{feerule.minlimit}}</view>

						<view v-if="collectway >  -2">可提现金额：{{balance}} <text @click="setmoney"
								style="color: red;font-size: blod;">{{' '}}全部提现</text></view>
						<view v-else-if="collectway ==  -2">可转余额：{{userinfo.balance}} <text
								@click="money = userinfo.balance" style="color: red;font-size: blod;">{{' '}}全部提现</text>
						</view>
						<view v-if="collectway >0">当前手续费：{{fee}}</view>
					</view>
				</view>

			</view>
		</view>


		<view class="box">
			<view class="box-child">

				<view class="choos-item">
					<view class="title-box">
						提现到
					</view>
					<view class="choose">

						<u-input v-model="collectwayTitle" placeholder="请选择提现方式" :select-open="show" input-align="right"
							type="select" @click="choosedraw" />

						<u-select v-model="show" :list="collectwaySelect" @confirm="confirm"></u-select>

					</view>

				</view>





			</view>
		</view>

		<u-popup mode="center" class="addbank" v-model="showform" :border-radius="10" @open="handelOpen" width="80%"
			@close="handelClose">
			<u-form :model="form" ref="uForm" :label-width="160" label-align="center" :error-type="['toast']">
				<u-form-item label="名称" prop="name" required>
					<u-input v-model="form.name" placeholder="请填写名称" />
				</u-form-item>
				<u-form-item label="提现方式">
					<u-input v-model="form.bankname" placeholder="请选择提现方式" :select-open="showbank" type="select"
						@click="showbank = true" />
				</u-form-item>
				<u-form-item label="提现账号" prop="account" required>
					<u-input v-model="form.account" placeholder="请填写提现账号" />
				</u-form-item>
				<u-form-item label="重复账号" prop="reaccount" required>
					<u-input v-model="form.reaccount" placeholder="请再次填写提现账号" />
				</u-form-item>
				<u-form-item label="真实姓名" prop="true_name" required>
					<u-input v-model="form.true_name" placeholder="请填写真实姓名" />
				</u-form-item>
				<u-form-item label="收款码" prop="collect_img" required v-if="[1,2,3].includes(form.bank)">
					<Upload v-model="form.collect_img" :customBtn="true" :addBtnIconSize="40" addBtnColor="#BCBDC2"
						uploadText="添加图片" :showProgress="true" />
						
				</u-form-item>
				<template v-if="needCertify">
					<u-form-item label="身份证号码" prop="card_no" required>
						<u-input v-model="form.card_no" placeholder="请填写身份证号码" />
					</u-form-item>
					<u-form-item label="手机号码" prop="mobile" required>
						<u-input v-model="form.mobile" placeholder="请填写手机号码" />
					</u-form-item>
				</template>
			</u-form>
			<u-button @click="submit">提交</u-button>
		</u-popup>
		<u-select v-model="showbank" :list="bankSelect" @confirm="confirmBank"></u-select>
		<view class="buy-button" @click="goodsBuy">
			立即提现
		</view>
		<OpenWind :show-type="2" ref='open_wind' title="佣金提现注意" />

		<password-input :popupShow.sync="showPassInput" @ok="handelPasswordInputOk" />

		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<qrcode-dialog ref="qrcode-dialog" @fail="handelCertifyFail" @success="handelCertifySuccess" />
	</view>
</template>

<script>
	import Upload from '@/components/upload/kuyu'
	import OpenWind from '@/components/OpenWind'
	import PasswordInput from '@/components/password-input/index'
	import slideCode from '@/components/slideCode.vue'
	import QrcodeDialog from './components/QrcodeDialog'
	import _ from 'lodash'

	export default {
		components: {
			Upload,
			OpenWind,
			'password-input': PasswordInput,
			slideCode,
			'qrcode-dialog': QrcodeDialog
		},
		data() {
			return {

				loading: false,
				scrollTop: 0,

				nav_opacity: 0,
				header_opacity: 1,

				tpl: {
					accountname: ''
				},
				userMobile: '',
				goods: { //当前选中商品
					id: 0,
					goods_name: '', //商品名称
					goods_img: '', //商品图片
					goods_info: '', //商品详情
					cate_name: '', //分类
					tpl: [], //模板
					goods_price: 0,
					face_value: 0,
				},
				//当前商品
				params: {


				},
				payConfig: {

				},

				defaultpay: '',
				payList: [

				],

				//当前支付订单号

				ordersn: '',
				order_id: '',
				total_price: 0,

				qrcode_title: '',
				qrcode_url: '',
				qrcodeshow: false,


				trade_password: '', //交易密码
				paystatusTimer: null,
				noneed_userinput_pass: false, //不需要输入交易密码
				input_pwd: false,
				input_finish: false, //交易密码是否输入完整

				qrcode_image_show: false,
				qrcode_image: '',

				qiehuan_img: '',
				money: '',
				type: 1,
				recharge_code: '',
				fee: '0.00', //手续费
				rate: 0,
				rate_min: '0.00',

				balance: '0.00',
				collectwayList: [],
				collectway: 0,
				collectwayTitle: '请选择提现方式',
				collectwaySelect: [],
				need_trade_password: false,
				feerule: {},
				show: false,


				showform: false,
				showbank: false,
				form: {
					name: '',
					bank: '',
					bankname: '',
					reaccount: '',
					account: '',
					true_name: '',
					id: '',
					collect_img: '',
					card_no: '',
					mobile: ''
				},
				rules: {
					name: [{
						required: true,
						message: '请输入名称',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
					account: [{
						required: true,
						message: '请输入提现账号',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
					reaccount: [{
							required: true,
							message: '请输入重复提现账号',
							// 可以单个或者同时写两个触发验证方式 
							trigger: ['change', 'blur'],
						},
						{
							validator: (rule, value, cb) => {
								// 如果对象中定义了message,这里的cb就不要用了
								// 必须返回true|false,如果不返回表示true
								// cb('123')
								if (this.form.account != value)
									return false
								else
									return true
							},
							message: '重复提现账号输入不正确',
							trigger: ['blur'],
						}
					],
					true_name: [{
						required: true,
						message: '请输入真实姓名',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
					collect_img: [{
						required: true,
						message: '请上传收款码',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
					card_no: [{
						required: true,
						message: '请输入身份证号码',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
					mobile: [{
						required: true,
						message: '请输入手机号码',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
				},
				bankList: [],
				bankSelect: [],
				showdraw: false,

				showPassInput: false,
				zfbCollectWayCertify: false,
				slideCode: [{
					show: false
				}],
				session_id: [], //会自动生成的
			}
		},
		computed: {
			needCertify() {
				if (
					!this.form.id &&
					this.zfbCollectWayCertify &&
					this.form.bank == 1
				)
					return true
				else return false
			},
			certifyForm() {
				return {
					card_no: this.form.card_no,
					real_name: this.form.true_name,
					mobile: this.form.mobile,
					type: 1,
					certify_type: 'authentication',
					collect_way_data: JSON.stringify({
						...this.form
					})
				}
			}
		},
		onReady() {

		},
		onLoad(e) {
			this.$slideCode_init(0); //初始化图形滑块
			this.loadData()
		},
		// 必须要在onReady生命周期，因为onLoad生命周期组件可能尚未创建完毕

		methods: {
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			choosedraw() {

				if (this.collectwaySelect.length == 0) {
					this.$util.msg('请先添加提现方式')
				} else {
					this.show = true
				}

			},
			async submit() {
				this.$refs.uForm.validate(valid => {
					if (valid) {
						console.log('验证通过');

						if (this.needCertify) {
							this.slideCode[0].show = true
						} else {
							this.save()
						}
					} else {
						console.log('验证失败');
					}
				})
			},
			async save() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				this.$u.api.drawmodeedit(this.form)
					.then(res => {
						this.$util.msg('申请成功,请等待审核')
						this.showform = false;
						setTimeout(() => {
							this.$util.on('/pages/ucenter_sub/drawmode')
						}, 1000)
					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()
			},
			//二维码生成成功
			uqrcodeComplete(e) {
				this.$refs.uqrcode.toTempFilePath({
					success: res => {
						this.qrcode_image = res.tempFilePath
						this.qrcode_image_show = true
					}
				});
			},
			copyLink() {
				uni.setClipboardData({
					data: this.qrcode_url,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
			async loadData() {

				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				await this.$u.api.drawConfig(this.params)
					.then(res => {


						this.balance = res.balance
						this.feerule = res.feerule
						this.collectwayList = res.collectway
						this.collectwaySelect = res.collectway
						// for (let i = 0; i < res.collectway.length; i++) {
						// 	this.collectwaySelect.push({
						// 		label: res.collectway[i].bank_name + '-' + res.collectway[i].account,
						// 		value: res.collectway[i].id,
						// 	})
						// }
						if (this.collectwaySelect.length > 0) {
							this.collectwayTitle = this.collectwaySelect[0].label
							this.collectway = this.collectwaySelect[0].value
						}

						//处理数据

						this.bankList = res.bankList
						this.bankSelect = res.bankList
						// for (let i = 0; i < res.bankList.length; i++) {
						// 	this.bankSelect.push({
						// 		label: res.bankList[i].k,
						// 		value: res.bankList[i].v,
						// 	})
						// }

						this.form.bankname = this.bankSelect[0].label
						this.form.bank = this.bankSelect[0].value

						// this.payList = res.payList
						// this.qiehuan_img = res.qiehuan_img

						// if (this.defaultpay == '') {
						// 	this.defaultpay = res.defaultpay
						// }



						// if (this.payList.length > 0) {
						// 	//手续费
						// 	for (let i = 0; i < this.payList.length; i++) {
						// 		if (this.payList[i].name == this.defaultpay) {
						// 			this.choosepay(this.payList[i]);
						// 		}

						// 	}
						// }

						if (res.member_collect_tip) {
							this.$refs['open_wind'].show(res.member_collect_tip)
						}
						this.need_trade_password = res.need_trade_password
						this.zfbCollectWayCertify = res.zfb_collect_way_certify
					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()
				// this.loading = false;
			},
			confirm(e) {
				this.collectwayTitle = e[0].label
				this.collectway = e[0].value
			},
			confirmBank(e) {
				this.form.bank = e[0].value
				this.form.bankname = e[0].label
			},
			setmoney() {
				this.money = this.balance
				this.getFee()
			},

			//选择支付方式
			choosepay(item) {
				this.defaultpay = item.name

				this.rate = item.rate
				this.rate_min = item.rate_min

				this.getFee()


			},
			//获取
			getFee() {
				if (this.money > 0) {


					//获取计算规则
					let rule = this.feerule.collectrule.split(',');

					let min = 0;
					let max = 0;
					let fee_rate = 0;
					let rate = []

					for (let i = 0; i < rule.length; i++) {
						rate = rule[i].split(':')
						min = parseInt(rate[0].split('-')[0])
						max = parseInt(rate[0].split('-')[1])

						if (fee_rate == 0 && i == 0 && this.money < min) {
							fee_rate = this.$util.bcmul(this.money, this.$util.bcdiv(rate[1], 100));
							break;
						}
						if (fee_rate == 0 && min <= this.money && max > this.money) {
							fee_rate = this.$util.bcmul(this.money, this.$util.bcdiv(rate[1], 100));
							break;
						}

						if (fee_rate == 0 && i == rule.length - 1 && this.money > max) {
							fee_rate = this.$util.bcmul(this.money, this.$util.bcdiv(rate[1], 100));
							break;
						}
					}


					this.fee = fee_rate

				} else {
					this.fee = '0.00'
				}
			},

			moneyInput(value) {
				this.getFee()
			},

			saveqrcode(e) {
				console.log(e);
			},
			//支付
			goodsBuy() {
				if (this.collectway > 0) {
					if (this.money <= 0) {
						this.$util.msg('提现金额有误')
						return;
					}
					if (this.balance < this.money) {
						this.$util.msg('可提现金额不足')
						return;
					}

					if (this.feerule.minlimit > this.money) {
						this.$util.msg('最小提现金额' + this.feerule.minlimit)
						return;
					}
				}
				if (this.need_trade_password) {
					this.showPassInput = true
				} else {
					this.doDraw()
				}
			},
			handelPasswordInputOk(e) {
				this.trade_password = e
				this.doDraw()
			},
			//加款卡充值
			codeRecharge() {

				this.$u.api.coderecharge({
					recharge_code: this.recharge_code,
				}).then((res) => {
					this.$util.msg(res.msg);

					this.$u.vuex('userinfo.balance', res.balance);
					setTimeout(() => {
						this.$util.on('/pages/ucenter/index');
					}, 1000)
				})
			},

			async doDraw() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				await this.$u.api.draw({
						money: this.money,
						collectway: this.collectway,
						trade_password: this.trade_password,
					})
					.then(res => {
						if (this.collectway == -1) {
							this.$util.msg('转余额成功')

							setTimeout(() => {
								this.$util.on('/pages/ucenter_sub/moneylist')
							}, 1000)
						} else if (this.collectway == -2) {
							this.$util.msg('转佣金成功')

							setTimeout(() => {
								this.$util.on('/pages/ucenter_sub/wallet')
							}, 1000)
						} else {
							this.$util.msg('提现申请提交成功，请等待审核')
							setTimeout(() => {
								// this.loadData()
								this.$util.on('/pages/ucenter_sub/drawlo')
							}, 1000)
						}
					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()

			},

			//分享
			share() {

			},

			// 提现方式弹框回调
			handelOpen() {
				this.$refs.uForm.setRules(this.rules);
			},
			handelClose() {
				const {
					name,
					bank,
					bankname
				} = this.form
				this.form = {
					...this.$options.data().form,
					name,
					bank,
					bankname
				}
			},
			async $slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值

				const newForm = _.cloneDeep(this.certifyForm)
				newForm.session = this.session_id[0]

				const {
					url
				} = await this.$u.api.userCertify(newForm)

				if (url) {
					this.$refs['qrcode-dialog'].show({
						url,
					})
				}
			},
			// 三方认证成功回调
			handelCertifySuccess({
				msg
			}) {
				this.$util.msg(msg)
				this.save()
			},
			// 三方认证失败回调
			handelCertifyFail({
				msg
			}) {
				this.$util.msg(msg)
			}
		}
	}
</script>


<style lang="scss" scoped scoped>
	.body {
		width: 100%;
		position: fixed;

		height: calc(100% - var(--window-top));
		overflow: hidden;
		background-color: #f4f5f8;
		display: flex;
		flex-direction: column;
		align-items: center;
	}

	.body .content {
		height: 100%;
	}


	.footer {


		z-index: 11;
		width: 100%;
		height: 98rpx;

		flex-wrap: nowrap;
		justify-content: space-between;
		align-items: center;
		display: flex;
		padding: 20rpx;

	}




	.footer .buyBtn {
		width: 320rpx;
		position: relative;
		display: flex;
		text-align: center;
		height: 80rpx;
		border-radius: 40rpx;
		background: #ccc;
		flex-direction: column;
		justify-content: center;
		font-weight: 700;
		color: #fff;
		background: #0e0d0d;
	}




	.box {
		position: relative;
		display: flex;
		align-items: center;
		flex-direction: column;
		z-index: 1;
	}

	.box .box-child {
		width: 726rpx;
		min-height: 88rpx;
		padding: 20rpx;
		margin-top: 20rpx;
		border-radius: 20rpx;
		display: flex;
		flex-direction: column;
		background-color: #fff;
		gap: 20rpx;


		.choos-item {
			display: flex;
			justify-content: space-between;

			flex-direction: row;
			align-items: center;

			padding-bottom: 10rpx;
		}

		.pay-list {
			display: flex;
			justify-content: flex-start;
			flex-direction: column;
			align-items: center;
